2	import ApiService from "@/common/api.service";
3	import JwtService from "@/common/jwt.service";
4	import { extractErrors } from "@/common/errors";
5	
6	export const useAuthStore = defineStore("auth", {
7	  state: () => ({
8	    errors: null,
9	    user: {},
10	    isAuthenticated: !!JwtService.getToken(),
11	    // 'authenticated' | 'unauthenticated' | 'unavailable'
12	    authStatus: JwtService.getToken() ? "authenticated" : "unauthenticated"
13	  }),
14	  getters: {
15	    currentUser: (state) => state.user
16	  },
17	  actions: {
18	    setAuth(user) {
19	      this.isAuthenticated = true;
20	      this.authStatus = "authenticated";
21	      this.user = user;
22	      this.errors = {};
23	      JwtService.saveToken(user.token);
24	    },
25	    setAuthUnavailable() {
26	      this.isAuthenticated = false;
27	      this.authStatus = "unavailable";
28	      this.user = {};
29	    },
30	    purgeAuth() {
31	      this.isAuthenticated = false;
32	      this.authStatus = "unauthenticated";
33	      this.user = {};
34	      this.errors = {};
35	      JwtService.destroyToken();
36	    },
37	    async login(credentials) {
38	      try {
39	        const { data } = await ApiService.post("users/login", {
40	          user: credentials
41	        });
42	        this.setAuth(data.user);
43	        return data;
44	      } catch (error) {
45	        this.errors = extractErrors(error);
46	        throw error;
47	      }
48	    },
49	    logout() {
50	      this.purgeAuth();
51	    },
52	    async register(credentials) {
53	      try {
54	        const { data } = await ApiService.post("users", { user: credentials });
55	        this.setAuth(data.user);
56	        return data;
57	      } catch (error) {
58	        this.errors = extractErrors(error);
59	        throw error;
60	      }
61	    },
62	    async checkAuth() {
63	      if (!JwtService.getToken()) {
64	        this.purgeAuth();
65	        return;
66	      }
67	      try {
68	        const { data } = await ApiService.get("user");
69	        if (data && data.user) {
70	          this.setAuth(data.user);
71	        } else {
72	          // 2XX without a parsable user payload (empty body, malformed
73	          // JSON): treat the server as unavailable but keep the token.
74	          this.setAuthUnavailable();
75	        }
76	      } catch (error) {
77	        const status = error && error.response && error.response.status;
78	        if (status >= 400 && status < 500) {
79	          // The token was rejected: clear it and show the logged-out UI.
80	          this.purgeAuth();
81	        } else {
82	          // 5XX or network failure: the token may still be valid, so keep
83	          // it and let the user browse in degraded mode.
84	          this.setAuthUnavailable();
85	        }
86	      }
87	    },
88	    async updateUser(payload) {
89	      const { email, username, password, image, bio } = payload;
90	      const user = {
91	        email,
92	        username,
93	        bio,
94	        image
95	      };
96	      if (password) {
97	        user.password = password;
98	      }
99	
100	      const { data } = await ApiService.put("user", { user });
101	      this.setAuth(data.user);
102	      return data;
103	    }
104	  }
105	});
